/**
 * @summary Compare multiple scenarios side by side
 */
export const getCompareScenariosUrl = (
  projectId: string,
  params: CompareScenariosParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/projects/${projectId}/compare?${stringifiedParams}`
    : `/api/projects/${projectId}/compare`;
};

export const compareScenarios = async (
  projectId: string,
  params: CompareScenariosParams,
  options?: RequestInit,
): Promise<ScenarioComparison> => {
  return customFetch<ScenarioComparison>(
    getCompareScenariosUrl(projectId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getCompareScenariosQueryKey = (
  projectId: string,
  params?: CompareScenariosParams,
) => {
  return [
    `/api/projects/${projectId}/compare`,
    ...(params ? [params] : []),
  ] as const;
};

export const getCompareScenariosQueryOptions = <
  TData = Awaited<ReturnType<typeof compareScenarios>>,
  TError = ErrorType<unknown>,
>(
  projectId: string,
  params: CompareScenariosParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof compareScenarios>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getCompareScenariosQueryKey(projectId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof compareScenarios>>
  > = ({ signal }) =>
    compareScenarios(projectId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!projectId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof compareScenarios>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type CompareScenariosQueryResult = NonNullable<
  Awaited<ReturnType<typeof compareScenarios>>
>;
export type CompareScenariosQueryError = ErrorType<unknown>;

/**
 * @summary Compare multiple scenarios side by side
 */

export function useCompareScenarios<
  TData = Awaited<ReturnType<typeof compareScenarios>>,
  TError = ErrorType<unknown>,
>(
  projectId: string,
  params: CompareScenariosParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof compareScenarios>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getCompareScenariosQueryOptions(
    projectId,
    params,
    options,
  );

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

